import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - finance-investment-researcher 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F07_存貨週轉效率同業對比_投資研究員.md"}'),n={name:"審計報告庫/財務審計/4967_十銓/20260428/F07_存貨週轉效率同業對比_投資研究員.md"};function l(o,a,s,c,h,d){return t(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-finance-investment-researcher-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - finance-investment-researcher 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - finance-investment-researcher 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：十銓DIO 156天同業中段，營運週期132→202天（+53%），策略性備貨致在途存貨翻倍，資金壓力升高。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年合併財報及優分析</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>評分</strong>：B（持平）</li><li><strong>重點數據</strong>：DIO 156天（創見212天、宇瞻134天）；存貨91.9億（+57.8%）；在途存貨30.6億（+90%）；營運週期202天（+70天）；跌價準備率5.4%</li><li><strong>診斷見解</strong>：營收+2.5%但毛利率躍升至14.3%（+3.1ppt），存貨暴增源於策略性備貨，營運週期拉長70天短期承壓，屬產業上行期主動選擇。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-週轉階差審核" tabindex="-1">1. 週轉階差審核 <a class="header-anchor" href="#_1-週轉階差審核" aria-label="Permalink to &quot;1. 週轉階差審核&quot;">​</a></h3><ul><li><strong>核心重點</strong>：十銓DIO逐季93d→100d→116d→124d上升，宇瞻Q4暴衝148d，創見226d→170d逐季改善。十銓在途存貨+90%（16.1億→30.6億），宇瞻年底存貨+109%（23億→48億）。</li><li><strong>深度見解</strong>：十銓與宇瞻Q4同步DIO暴增但動機各異——十銓指向海外低價採購，宇瞻為前瞻備貨。創見DIO持續下降反映存貨管理優於同業，但代價是營收增長受限。</li></ul><h3 id="_2-營運週期透視" tabindex="-1">2. 營運週期透視 <a class="header-anchor" href="#_2-營運週期透視" aria-label="Permalink to &quot;2. 營運週期透視&quot;">​</a></h3><ul><li><strong>核心重點</strong>：營運週期（DIO+DSO）從~132天擴至~202天（+70天），DSO從~38天升至~46天。以營收204.3億估算，額外資金佔用~39.2億，借款從11.0億暴增至33.2億（+202%）。</li><li><strong>深度見解</strong>：營運資金被鎖定時間增53%，公司以舉債填補缺口。若記憶體價格如期上漲，持有收益將遠超資金成本。</li></ul><h3 id="_3-通路博弈分析" tabindex="-1">3. 通路博弈分析 <a class="header-anchor" href="#_3-通路博弈分析" aria-label="Permalink to &quot;3. 通路博弈分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：美洲市場佔營收69.5%，DRAM佔比從79.3%降至71.0%，FLASH從17.8%升至27.0%，產品組合多元化分散存貨風險。賠償損失3,457萬。</li><li><strong>深度見解</strong>：毛利率從11.2%躍升至14.3%證明產品組合優化，但賠償損失可能反映通路合約糾紛，需關注對通路關係的影響。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一－在途存貨翻倍遇需求反轉恐巨額跌價</strong>：在途存貨從16.1億暴增至30.6億（+90%），若DDR5需求不如預期或AI PC渗透率放緩，這批高價備貨將面臨大規模跌價損失。以5.4%準備率估算，額外10%價格下跌將造成~9.2億額外備抵，幾乎等於全年淨利。存貨跌價非線性——一旦價格反轉，跌價速度遠快於備貨速度。</li><li><strong>空頭風險二－營收增2.5%對比存貨增57%，增速背離顯去化壓力</strong>：營收僅溫和增長2.5%，但存貨暴增57.8%，兩者增速嚴重背離。這不是「策略性備貨」能完全解釋的——若DDR5價格回落，71%的DRAM營收佔比將直接暴露在價格風險敞口下。歷史經驗顯示記憶體價格週期約18-24個月，目前處於上行尾段，一旦反轉，高庫存將從資產變為負擔。</li><li><strong>空頭風險三－DDR5價格回落侵蝕毛利</strong>：十銓DRAM佔營收71%，DDR5合約價若從當前水平回落15%，毛利率將從14.3%回落至~11.5%，淨利可能腰斬。目前高毛利率建立在DDR5溢價基礎上，一旦供過於求，價格戰將壓縮所有記憶體模組廠的利潤空間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: OK - TaiwanStockFinancialStatements與TaiwanStockBalanceSheet數據完整</li><li><strong>yfinance</strong>: OK - 4967.TW/2451.TW/8271.TW財報交叉比對一致</li><li><strong>年報</strong>: OK - 2025年合併財報第31頁存貨附註、第11頁資產負債表</li><li><strong>優分析</strong>: OK - 季度DIO數據與年報交叉比對一致</li><li><strong>關鍵核對碼</strong>: DIO = (5,823M+9,191M)/2 ÷ 17,514M × 365 = 156天；營運週期擴張 = 202d - 132d = +70天</li></ul>',19)])])}const u=e(n,[["render",l]]);export{g as __pageData,u as default};
